#include &lt;unistd.h&gt;
#include &lt;errno.h&gt;
#include &lt;stdio.h&gt;

// A highly resilient wrapper around the raw read() system call
ssize_t robust_read(int fd, void *buf, size_t count) {
    size_t bytes_left = count;
    ssize_t bytes_read;
    char *ptr = (char *)buf;

    while (bytes_left > 0) {
        // Request data from the Kernel
        bytes_read = read(fd, ptr, bytes_left);

        if (bytes_read < 0) {
            // The OS Kernel was busy processing a Signal (like an alarm or Ctrl+C).
            // The read was interrupted before any data was transferred. Try again.
            if (errno == EINTR) {
                continue; 
            }
            return -1; // A true fatal hardware or network error occurred.

        } else if (bytes_read == 0) {
            // End of File (EOF) or client disconnect.
            break; 
        }

        // Advance the buffer pointer by exactly the amount we successfully read
        bytes_left -= bytes_read;
        ptr += bytes_read;
    }

    // Return the total bytes mathematically accumulated
    return (count - bytes_left);
}

#include &lt;fcntl.h&gt;
#include &lt;stdio.h&gt;

void create_log_file() {
    // Engineer wants to create a new log file if it doesn't exist.
    // They correctly specify O_CREAT.
    int fd = open("application.log", O_WRONLY | O_CREAT);

    if (fd == -1) {
        perror("Failed to create file");
    } else {
        printf("Log file created successfully.\n");
    }
}
